#!/bin/bash
set -e
C=hermes-agent-c7dm-hermes-agent-1
echo "== ko-bets fresh deploy =="
echo "[1/7] container check"
docker ps --format "{{.Names}}" | grep -q "^$C$" || { echo "ERROR: container $C not running"; docker ps --format "  {{.Names}}"; exit 1; }
docker exec $C mkdir -p /home/hermes/sites/ko-bets /home/hermes/logs
echo "[2/7] writing agent files"
echo "" | docker exec -i $C bash -c "base64 -d > /home/hermes/sites/ko-bets/lib_wp.py"
echo "" | docker exec -i $C bash -c "base64 -d > /home/hermes/sites/ko-bets/agent_content.py"
echo "" | docker exec -i $C bash -c "base64 -d > /home/hermes/sites/ko-bets/agent_grade_picks.py"
echo "" | docker exec -i $C bash -c "base64 -d > /home/hermes/sites/ko-bets/api_bridge.py"
echo "" | docker exec -i $C bash -c "base64 -d > /home/hermes/sites/ko-bets/site-config.json"
echo "" | docker exec -i $C bash -c "base64 -d > /home/hermes/sites/ko-bets/run.sh"
docker exec $C chmod +x /home/hermes/sites/ko-bets/run.sh
echo "[3/7] writing .env (WP creds + container API keys, for cron)"
docker exec $C bash -lc 'set -e; echo KOBETS_WP_URL=https://ko-bets.com > /home/hermes/sites/ko-bets/.env; echo KOBETS_WP_USER=kobets619@gmail.com >> /home/hermes/sites/ko-bets/.env; echo KOBETS_WP_APP_PASSWORD=${KOBETS_WP_APP_PASSWORD_REDACTED_SET_MANUALLY} >> /home/hermes/sites/ko-bets/.env; echo KOBETS_MODEL=claude-haiku-4-5-20251001 >> /home/hermes/sites/ko-bets/.env; if [ -n "$ANTHROPIC_API_KEY" ]; then echo ANTHROPIC_API_KEY=$ANTHROPIC_API_KEY >> /home/hermes/sites/ko-bets/.env; else echo "WARN: ANTHROPIC_API_KEY empty in container env"; fi; if [ -n "$GEMINI_API_KEY" ]; then echo GEMINI_API_KEY=$GEMINI_API_KEY >> /home/hermes/sites/ko-bets/.env; fi; chmod 600 /home/hermes/sites/ko-bets/.env; echo ".env written:"; grep -c = /home/hermes/sites/ko-bets/.env'
echo "[4/7] installing python deps"
docker exec $C bash -lc 'PY=$( [ -x /opt/hermes/.venv/bin/python3 ] && echo /opt/hermes/.venv/bin/python3 || command -v python3 ); echo using $PY; $PY -m pip --version >/dev/null 2>&1 || (curl -sS https://bootstrap.pypa.io/get-pip.py | $PY); ($PY -m pip install -q --upgrade requests anthropic python-dotenv 2>&1 || $PY -m pip install -q --upgrade requests anthropic python-dotenv --break-system-packages 2>&1) | tail -3; $PY -c "import requests, anthropic; print(\"deps OK\")"'
echo "[5/7] installing + starting cron"
docker exec $C bash -lc 'set -e; (command -v cron >/dev/null 2>&1 || (apt-get update -qq && apt-get install -y -qq cron)); service cron start 2>/dev/null || cron 2>/dev/null || true; ( crontab -l 2>/dev/null | grep -v "ko-bets/run.sh" || true; echo "SHELL=/bin/bash"; echo "0 6,12,20 * * * /home/hermes/sites/ko-bets/run.sh api_bridge.py --once >> /home/hermes/logs/kobets.log 2>&1"; echo "15 23 * * 2 /home/hermes/sites/ko-bets/run.sh agent_content.py --weekly >> /home/hermes/logs/kobets.log 2>&1"; echo "15 23 * * 5 /home/hermes/sites/ko-bets/run.sh agent_content.py --weekly >> /home/hermes/logs/kobets.log 2>&1"; echo "30 23 * * * /home/hermes/sites/ko-bets/run.sh agent_grade_picks.py >> /home/hermes/logs/kobets.log 2>&1" ) | crontab -; echo "cron jobs:"; crontab -l | grep run.sh | wc -l'
echo "[6/7] WP self-test"
docker exec $C bash -lc "/home/hermes/sites/ko-bets/run.sh lib_wp.py --selftest"
echo "[7/7] generating first Fight Analysis posts"
docker exec $C bash -lc "/home/hermes/sites/ko-bets/run.sh agent_content.py --weekly"
echo "== DEPLOY COMPLETE =="
